{
  "mode": "method",
  "tests": [
    {
      "name": "valid_scorecard_details",
      "input": {
        "challengeId": "12345",
        "userId": "67890"
      },
      "output": {
        "score": 85,
        "comments": ["Well done!", "Needs improvement in design."],
        "appeals": []
      },
      "args": [],
      "kwargs": {},
      "notes": "Valid input should return scorecard details with actual data."
    },
    {
      "name": "empty_scorecard_details",
      "input": {
        "challengeId": "54321",
        "userId": "09876"
      },
      "output": {
        "score": null,
        "comments": [],
        "appeals": []
      },
      "args": [],
      "kwargs": {},
      "notes": "Input with no existing scorecard should return empty details."
    },
    {
      "name": "invalid_challenge_id",
      "input": {
        "challengeId": "invalid_id",
        "userId": "67890"
      },
      "output": {
        "error": "Challenge not found"
      },
      "args": [],
      "kwargs": {},
      "notes": "Invalid challenge ID should return an error."
    },
    {
      "name": "unauthorized_user_access",
      "input": {
        "challengeId": "12345",
        "userId": "not_authorized_user"
      },
      "output": {
        "error": "Unauthorized access"
      },
      "args": [],
      "kwargs": {},
      "notes": "User without proper role should be denied access."
    },
    {
      "name": "valid_appeal_creation",
      "input": {
        "challengeId": "12345",
        "userId": "67890",
        "appeal": {
          "reason": "Disagreement with score",
          "details": "The design was more innovative."
        }
      },
      "output": {
        "success": true,
        "appealId": "appeal_001"
      },
      "args": [],
      "kwargs": {},
      "notes": "Valid appeal creation should return success and appeal ID."
    },
    {
      "name": "duplicate_appeal_submission",
      "input": {
        "challengeId": "12345",
        "userId": "67890",
        "appeal": {
          "reason": "Disagreement with score",
          "details": "The design was more innovative."
        }
      },
      "output": {
        "error": "Duplicate appeal submission"
      },
      "args": [],
      "kwargs": {},
      "notes": "Submitting the same appeal twice should return an error."
    },
    {
      "name": "valid_appeal_response",
      "input": {
        "appealId": "appeal_001",
        "response": {
          "status": "accepted",
          "comments": "Your points are valid."
        }
      },
      "output": {
        "success": true,
        "responseId": "response_001"
      },
      "args": [],
      "kwargs": {},
      "notes": "Valid appeal response should return success and response ID."
    },
    {
      "name": "invalid_appeal_response",
      "input": {
        "appealId": "invalid_appeal_id",
        "response": {
          "status": "accepted",
          "comments": "Your points are valid."
        }
      },
      "output": {
        "error": "Appeal not found"
      },
      "args": [],
      "kwargs": {},
      "notes": "Responding to a non-existent appeal should return an error."
    }
  ],
